using Microsoft.Build.Logging.StructuredLogger;
using System;
using System.Collections.Generic;
using System.Linq;

var binlogPath = args.Length > 0 ? args[0] : "build.binlog";
var build = BinaryLog.ReadBuild(binlogPath);

Console.WriteLine("=== BUILD RESULT ===");
Console.WriteLine($"Succeeded: {build.Succeeded}");
Console.WriteLine();

// Collect all errors and warnings
var errors = new List<(string Project, string File, int Line, int Col, string Code, string Message, string Subcategory)>();
var warnings = new List<(string Project, string File, int Line, int Col, string Code, string Message)>();

void Visit(BaseNode node, string currentProject = "")
{
    if (node is Project p)
        currentProject = p.Name;
    if (node is Microsoft.Build.Logging.StructuredLogger.Error e)
        errors.Add((currentProject, e.File ?? "", e.LineNumber, e.ColumnNumber, e.Code ?? "", e.Text ?? e.ToString(), e.Subcategory ?? ""));
    if (node is Warning w)
        warnings.Add((currentProject, w.File ?? "", w.LineNumber, w.ColumnNumber, w.Code ?? "", w.Text ?? w.ToString()));

    if (node is TreeNode tree)
        foreach (var child in tree.Children.OfType<BaseNode>())
            Visit(child, currentProject);
}

Visit(build);

Console.WriteLine($"=== ERRORS ({errors.Count}) ===");
foreach (var (proj, file, line, col, code, msg, subcat) in errors)
{
    Console.WriteLine($"[{code}] Project: {proj}");
    Console.WriteLine($"  File: {file}:{line}:{col}");
    Console.WriteLine($"  Message: {msg}");
    if (!string.IsNullOrEmpty(subcat))
        Console.WriteLine($"  Subcategory: {subcat}");
    Console.WriteLine();
}

Console.WriteLine($"=== WARNINGS ({warnings.Count}) ===");
foreach (var (proj, file, line, col, code, msg) in warnings)
{
    Console.WriteLine($"[{code}] Project: {proj}");
    Console.WriteLine($"  File: {file}:{line}:{col}");
    Console.WriteLine($"  Message: {msg}");
    Console.WriteLine();
}

// Show project dependency info
Console.WriteLine("=== PROJECT BUILD ORDER & DEPENDENCIES ===");
void VisitProjects(BaseNode node, int depth = 0)
{
    if (node is Project p2)
    {
        var indent = new string(' ', depth * 2);
        var hasErrors = errors.Any(e => e.Project == p2.Name);
        Console.WriteLine($"{indent}Project: {p2.Name} (Target: {p2.TargetFramework}) {(hasErrors ? "[HAS ERRORS]" : "[OK]")}");
    }
    if (node is TreeNode tree2)
        foreach (var child in tree2.Children.OfType<BaseNode>())
            VisitProjects(child, node is Project ? depth + 1 : depth);
}
VisitProjects(build);

