using Microsoft.Build.Logging.StructuredLogger;
using System;
using System.Collections.Generic;
using System.Linq;

var binlogPath = args.Length > 0 ? args[0] : "build.binlog";
var build = BinaryLog.ReadBuild(binlogPath);

// Extract items (PackageReference, ProjectReference) and properties from each project
void VisitDetailed(BaseNode node, string currentProject = "", int depth = 0)
{
    if (node is Project p)
    {
        currentProject = p.Name;
        Console.WriteLine($"\n=== Project: {p.Name} | Source: {p.ProjectFile} ===");
    }

    if (node is Folder f && (f.Name == "Items" || f.Name == "Properties"))
    {
        // Only print interesting items
    }

    if (node is AddItem addItem)
    {
        if (addItem.Name == "PackageReference" || addItem.Name == "ProjectReference" || addItem.Name == "Reference")
        {
            Console.WriteLine($"  [{addItem.Name}]");
            foreach (var child in addItem.Children.OfType<Item>())
                Console.WriteLine($"    - {child.Text}");
        }
    }

    // Look for SourceFile items  
    if (node is NamedNode nn && nn.Name == "Csc")
    {
        Console.WriteLine($"  [Csc Task in {currentProject}]");
        if (node is TreeNode cscTree)
        {
            foreach (var child in cscTree.Children.OfType<BaseNode>())
            {
                if (child is Folder folder)
                {
                    Console.WriteLine($"    Folder: {folder.Name}");
                    foreach (var item in folder.Children.OfType<BaseNode>().Take(30))
                        Console.WriteLine($"      {item}");
                }
                else if (child is Microsoft.Build.Logging.StructuredLogger.Parameter param)
                {
                    if (param.Name == "Sources" || param.Name == "References" || param.Name.Contains("Reference"))
                        Console.WriteLine($"    Param: {param.Name} = {param.ToString()?.Substring(0, Math.Min(200, param.ToString()?.Length ?? 0))}");
                }
            }
        }
    }

    if (node is TreeNode tree)
        foreach (var child in tree.Children.OfType<BaseNode>())
            VisitDetailed(child, currentProject, depth + 1);
}

VisitDetailed(build);

// Also look for source file text embedded in the binlog
Console.WriteLine("\n\n=== SEARCHING FOR SOURCE FILE CONTENT ===");
void FindSourceContent(BaseNode node, string currentProject = "")
{
    if (node is Project p)
        currentProject = p.Name;

    if (node is SourceFile sf)
        Console.WriteLine($"  SourceFile in {currentProject}: {sf}");

    if (node is SourceFileLine sfl)
        Console.WriteLine($"  SourceFileLine: {sfl}");

    if (node is TextNode tn && tn.Text != null && tn.Text.Contains("using"))
    {
        var text = tn.Text;
        if (text.Length < 500)
            Console.WriteLine($"  TextNode [{tn.GetType().Name}] in {currentProject}: {text}");
    }

    if (node is TreeNode tree)
        foreach (var child in tree.Children.OfType<BaseNode>())
            FindSourceContent(child, currentProject);
}
FindSourceContent(build);

// Dump all node types to understand what we have
Console.WriteLine("\n\n=== ALL NODE TYPES ===");
var nodeTypes = new HashSet<string>();
void CollectTypes(BaseNode node)
{
    nodeTypes.Add(node.GetType().Name);
    if (node is TreeNode tree)
        foreach (var child in tree.Children.OfType<BaseNode>())
            CollectTypes(child);
}
CollectTypes(build);
foreach (var t in nodeTypes.OrderBy(x => x))
    Console.WriteLine($"  {t}");
