cat > /tmp/binlog-reader/Program.cs << 'CSHARP'
using Microsoft.Build.Logging.StructuredLogger;
using System;
using System.Collections.Generic;
using System.Linq;

var binlogPath = args.Length > 0 ? args[0] : "build.binlog";
var build = BinaryLog.ReadBuild(binlogPath);

// Focus: find PackageReference items, project structure, and errors
var projectPackages = new Dictionary<string, List<string>>();
var projectRefs = new Dictionary<string, List<string>>();

void Visit(BaseNode node, string currentProject = "")
{
    if (node is Project p)
        currentProject = p.Name;

    if (node is AddItem addItem && !string.IsNullOrEmpty(currentProject))
    {
        if (addItem.Name == "PackageReference")
        {
            if (!projectPackages.ContainsKey(currentProject))
                projectPackages[currentProject] = new List<string>();
            foreach (var child in addItem.Children.OfType<Item>())
                if (!projectPackages[currentProject].Contains(child.Text))
                    projectPackages[currentProject].Add(child.Text);
        }
        if (addItem.Name == "ProjectReference")
        {
            if (!projectRefs.ContainsKey(currentProject))
                projectRefs[currentProject] = new List<string>();
            foreach (var child in addItem.Children.OfType<Item>())
                if (!projectRefs[currentProject].Contains(child.Text))
                    projectRefs[currentProject].Add(child.Text);
        }
    }

    if (node is TreeNode tree)
        foreach (var child in tree.Children.OfType<BaseNode>())
            Visit(child, currentProject);
}

Visit(build);

Console.WriteLine("=== PACKAGE REFERENCES BY PROJECT ===");
foreach (var kvp in projectPackages)
{
    Console.WriteLine($"  {kvp.Key}:");
    foreach (var pkg in kvp.Value)
        Console.WriteLine($"    - {pkg}");
}

Console.WriteLine("\n=== PROJECT REFERENCES BY PROJECT ===");
foreach (var kvp in projectRefs)
{
    Console.WriteLine($"  {kvp.Key}:");
    foreach (var r in kvp.Value)
        Console.WriteLine($"    - {r}");
}

// Extract source file lines from errors to understand usage
Console.WriteLine("\n=== ERROR SOURCE CONTEXT ===");
void FindErrors(BaseNode node, string currentProject = "")
{
    if (node is Project p2)
        currentProject = p2.Name;
    if (node is Microsoft.Build.Logging.StructuredLogger.Error e)
    {
        Console.WriteLine($"  [{e.Code}] {currentProject} -> {e.File}:{e.LineNumber}:{e.ColumnNumber}");
        Console.WriteLine($"    {e.Text}");
    }
    if (node is TreeNode tree)
        foreach (var child in tree.Children.OfType<BaseNode>())
            FindErrors(child, currentProject);
}
FindErrors(build);

// Check if Api.csproj had any build failures or if it depends on Services
Console.WriteLine("\n=== CHECKING CASCADING FAILURES ===");
var errors = new List<(string Project, string Code, string Message)>();
void CollectErrors(BaseNode node, string currentProject = "")
{
    if (node is Project p3)
        currentProject = p3.Name;
    if (node is Microsoft.Build.Logging.StructuredLogger.Error e2)
        errors.Add((currentProject, e2.Code ?? "", e2.Text ?? ""));
    if (node is TreeNode tree)
        foreach (var child in tree.Children.OfType<BaseNode>())
            CollectErrors(child, currentProject);
}
CollectErrors(build);

var failedProjects = errors.Select(e => e.Project).Distinct().ToList();
Console.WriteLine($"  Failed projects: {string.Join(", ", failedProjects)}");

foreach (var kvp in projectRefs)
{
    var dependsOnFailed = kvp.Value.Any(r => failedProjects.Any(fp => r.Contains(fp.Replace(".csproj", ""))));
    if (dependsOnFailed)
        Console.WriteLine($"  {kvp.Key} depends on failed project(s): {string.Join(", ", kvp.Value.Where(r => failedProjects.Any(fp => r.Contains(fp.Replace(".csproj", "")))))}");
}
