var build = BinaryLog.ReadBuild(binlogPath);

// Find if Newtonsoft.Json appears anywhere
int count = 0;
void FindNewtonsoft(BaseNode node)
{
    string text = null;
    if (node is NamedNode nn) text = nn.Name;
    else if (node is TextNode tn) text = tn.Text;

    var str = node.ToString();
    if ((text?.Contains("Newtonsoft") == true || str?.Contains("Newtonsoft") == true) && count < 30)
    {
        Console.WriteLine($"  [{node.GetType().Name}] {str?.Substring(0, Math.Min(500, str?.Length ?? 0))}");
        count++;
    }
    if (node is TreeNode tree)
        foreach (var child in tree.Children.OfType<BaseNode>())
            FindNewtonsoft(child);
}
FindNewtonsoft(build);
Console.WriteLine($"\nTotal Newtonsoft mentions found: {count}");

// Also check PackageReference items specifically
Console.WriteLine("\n=== ALL PackageReference AddItems ===");
void FindPackageRefs(BaseNode node, string proj = "")
{
    if (node is Project p) proj = p.Name;
    if (node is AddItem ai && ai.Name == "PackageReference")
    {
        foreach (var child in ai.Children.OfType<Item>())
            Console.WriteLine($"  {proj}: {child.Text}");
    }
    if (node is TreeNode tree)
        foreach (var child in tree.Children.OfType<BaseNode>())
            FindPackageRefs(child, proj);
}
FindPackageRefs(build);

