Console.WriteLine("\n=== EMBEDDED FILES (first 50) ===");
var archives = build.SourceFiles;
if (archives != null)
{
    Console.WriteLine($"  SourceFiles count: {archives.Count}");
    foreach (var kvp in archives.Take(50))
        Console.WriteLine($"  File: {kvp.Key} ({kvp.Value?.Length ?? 0} bytes)");
}
else
{
    Console.WriteLine("  No embedded source files.");
    // Try the SourceFilesArchive
    var archive = build.SourceFilesArchive;
    if (archive != null)
    {
        Console.WriteLine($"  SourceFilesArchive: {archive.Length} bytes");
    }
    else
    {
        Console.WriteLine("  No SourceFilesArchive either.");
    }
}
